import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetime, timedeltaimport urllib.parseimport plotly.express as pximport warnings# Gereksiz uyarıları gizlewarnings.filterwarnings("ignore")# --- 1. SAYFA AYARLARI ---st.set_page_config(    page_title="Bostanlı Çözüm VIP",     layout="wide",     page_icon="🏫",    initial_sidebar_state="collapsed" )# Arayüz temizleme ve Tasarım (CSS)st.markdown("""    <style>    #MainMenu {visibility: hidden;}    footer {visibility: hidden;}    header {visibility: hidden;}    .stDeployButton {display:none;}    .stTabs [data-baseweb="tab-list"] {        gap: 10px;        background-color: #f0f2f6;        padding: 10px;        border-radius: 10px;    }    .stTabs [data-baseweb="tab"] {        height: 50px;        white-space: pre-wrap;        background-color: #ffffff;        border-radius: 5px;        padding: 10px 20px;        font-weight: bold;    }    </style>    """, unsafe_allow_html=True)# --- 2. ÇİFTLİ ŞİFRE SİSTEMİ ---def check_password():    if "user_role" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        pwd = st.text_input("Giriş Şifresi", type="password")        if st.button("Sisteme Giriş Yap"):            if pwd == "cozum35":                st.session_state["user_role"] = "admin"                st.rerun()            elif pwd == "personel35":                st.session_state["user_role"] = "staff"                st.rerun()            else:                st.error("❌ Hatalı şifre.")        return False    return Trueif check_password():    conn = st.connection("gsheets", type=GSheetsConnection)    role = st.session_state["user_role"]    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # --- 3. ÜST BAŞLIK VE ÇIKIŞ ---    c_title, c_exit = st.columns([4, 1])    with c_title:        st.title(f"🏫 Bostanlı Çözüm VIP ({'Kurucu' if role == 'admin' else 'Personel'} Paneli)")    with c_exit:        if st.button("🚪 Güvenli Çıkış"):            del st.session_state["user_role"]            st.rerun()    # --- 4. YETKİYE GÖRE SEKMELER ---    if role == "admin":        tabs = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📊 Kurucu Raporu", "📈 Gelişmiş Analiz"])    else:        tabs = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📝 Kurucuya Rapor Gönder"])    # --- 📞 TAB 1: VELİ GÖRÜŞMELERİ ---    with tabs[0]:        st.header("📞 Veli Görüşme Kayıt & Düzenleme")        try:            df_v = conn.read(worksheet="gorusmeler", ttl=0)        except:            df_v = pd.DataFrame(columns=["Tarih", "Veli Ad Soyad", "Öğrenci Ad Soyad", "Telefon", "Konu", "Durum", "Notlar"])                # Yeni Kayıt Formu        with st.expander("➕ Yeni Görüşme Ekle", expanded=True):            with st.form("v_form", clear_on_submit=True):                v_tarih = st.date_input("Görüşme Tarihi", datetime.now(), format="DD/MM/YYYY")                c1, c2 = st.columns(2)                v_ad = c1.text_input("Veli Ad Soyad *")                o_ad = c1.text_input("Öğrenci Ad Soyad *")                v_tel = c2.text_input("Telefon Numarası *")                v_konu = c2.selectbox("Konu *", ["Seçiniz...", "Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Ara Sınıf Hazırlık", "Online Kamp", "Yüz Yüze Kamp", "Kayıt Silme", "Diğer"])                v_durum = st.selectbox("Durum *", ["Seçiniz...", "Beklemede", "Olumlu", "Olumsuz", "Kayıt Tamamlandı", "İptal"])                v_not = st.text_area("Görüşme Notları *")                                if st.form_submit_button("Kaydı Tamamla"):                    if v_ad and o_ad and v_tel and v_konu != "Seçiniz...":                        new = pd.DataFrame([{"Tarih": v_tarih.strftime("%Y-%m-%d"), "Veli Ad Soyad": v_ad, "Öğrenci Ad Soyad": o_ad, "Telefon": v_tel, "Konu": v_konu, "Durum": v_durum, "Notlar": v_not}])                        conn.update(worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                        st.success(f"✅ Kayıt başarıyla tamamlandı.")                        st.markdown(f'### [👉 Velimize Mesaj Gönder]({wa_link(v_tel, f"Sayın {v_ad}, bugün {o_ad} için görüşmemiz için teşekkür ederiz.")})')                    else:                        st.error("⚠️ Eksik alanları doldurun!")        # Kayıt Düzenleme Alanı        st.subheader("🔍 Kayıtları Gör ve Düzenle")        st.info("Aşağıdaki tabloyu kullanarak geçmiş kayıtları görebilir ve üzerine tıklayarak düzenleyebilirsiniz.")        # Data Editor sayesinde personel kendi girdiği kaydı düzenleyebilir        edited_df_v = st.data_editor(df_v, num_rows="dynamic", use_container_width=True, key="edit_v")        if st.button("📞 Görüşme Listesini Güncelle"):            conn.update(worksheet="gorusmeler", data=edited_df_v)            st.success("Görüşme listesi başarıyla güncellendi!")    # --- 💰 TAB 2: KASA İŞLEMLERİ ---    with tabs[1]:        st.header("💰 Kasa İşlemleri & Düzenleme")        try:            df_k = conn.read(worksheet="kasa", ttl=0)        except:            df_k = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])        with st.expander("➕ Yeni Kasa İşlemi Ekle"):            k_tarih = st.date_input("İşlem Tarihi", datetime.now(), format="DD/MM/YYYY")            k_tip = st.radio("İşlem Türü:", ["Gelir (Tahsilat)", "Gider (Ödeme)"], horizontal=True)            k_kalemler = ["Aidat Ödemesi", "Yayın Paketi Ödemesi", "Özel Ders", "Kira", "Maaş", "Fatura", "Diğer"]            k_kat = st.selectbox("Kategori *", k_kalemler)            k_tutar = st.number_input("Tutar (TL) *", min_value=0.0)            k_detay = st.text_input("Açıklama *")            if st.button("Kasaya Kaydet"):                if k_tutar > 0 and k_detay:                    new_k = pd.DataFrame([{"Tarih": k_tarih.strftime("%Y-%m-%d"), "Tip": k_tip, "Kategori": k_kat, "Miktar": k_tutar, "Detay": k_detay}])                    conn.update(worksheet="kasa", data=pd.concat([df_k, new_k], ignore_index=True))                    st.success("Kasa güncellendi!")        st.subheader("🔍 Kasa Hareketleri")        edited_df_k = st.data_editor(df_k, num_rows="dynamic", use_container_width=True, key="edit_k")        if st.button("💰 Kasa Listesini Güncelle"):            conn.update(worksheet="kasa", data=edited_df_k)            st.success("Kasa hareketleri başarıyla güncellendi!")    # --- 🚨 TAB 3: GÜNLÜK OLAYLAR ---    with tabs[2]:        st.header("🚨 Günlük Olay Kaydı")        try:            df_o = conn.read(worksheet="olaylar", ttl=0)        except:            df_o = pd.DataFrame(columns=["Tarih", "Olay Tipi", "Detay"])                o_t = st.date_input("Olay Tarihi", datetime.now())        o_tip = st.selectbox("Tip", ["Acil Durum", "Ziyaretçi", "Şikayet", "Teknik", "Diğer"])        o_det = st.text_area("Detay")        if st.button("Olayı Kaydet"):            new_o = pd.DataFrame([{"Tarih": o_t.strftime("%Y-%m-%d"), "Olay Tipi": o_tip, "Detay": o_det}])            conn.update(worksheet="olaylar", data=pd.concat([df_o, new_o], ignore_index=True))            st.success("Olay kaydedildi.")    # --- 📊 RAPORLAMA FONKSİYONU ---    def generate_detailed_report(target_date_str):        try:            dv = conn.read(worksheet="gorusmeler", ttl=0)            dk = conn.read(worksheet="kasa", ttl=0)            do = conn.read(worksheet="olaylar", ttl=0)                        # Tarih kolonlarını string'e çevirip filtreleme yapıyoruz            dv_b = dv[dv['Tarih'].astype(str).str.contains(target_date_str, na=False)]            dk_b = dk[dk['Tarih'].astype(str).str.contains(target_date_str, na=False)]            do_b = do[do['Tarih'].astype(str).str.contains(target_date_str, na=False)]                        dk_b['Miktar'] = pd.to_numeric(dk_b['Miktar'], errors='coerce').fillna(0)            gelir_df = dk_b[dk_b['Tip'] == 'Gelir (Tahsilat)']            gider_df = dk_b[dk_b['Tip'] == 'Gider (Ödeme)']                        t_gelir = gelir_df['Miktar'].sum()            t_gider = gider_df['Miktar'].sum()            msg = f"*🏫 BOSTANLI ÇÖZÜM VIP RAPOR ({datetime.strptime(target_date_str, '%Y-%m-%d').strftime('%d.%m.%Y')})*\n"            msg += f"💰 Gelir: {t_gelir:,.0f} TL | 💸 Gider: {t_gider:,.0f} TL\n\n"            if not dv_b.empty:                msg += "*📞 GÖRÜŞMELER:*\n"                for _, r in dv_b.iterrows(): msg += f"- {r['Öğrenci Ad Soyad']} ({r['Konu']})\n"                        return {"msg": msg, "data": {"dv_b": dv_b, "gelir_df": gelir_df, "gider_df": gider_df, "do_b": do_b, "t_gelir": t_gelir, "t_gider": t_gider}}        except: return None    # --- 📊 TAB 4: KURUCU RAPORU (ADMIN) ---    if role == "admin":        with tabs[3]:            st.header("📊 Günlük Detaylı Rapor")            t_sec_raw = st.date_input("Rapor Tarihi Seç", datetime.now(), format="DD/MM/YYYY")            report = generate_detailed_report(t_sec_raw.strftime("%Y-%m-%d"))            if report:                d = report["data"]                st.metric("Net Kasa", f"{d['t_gelir'] - d['t_gider']:,.0f} TL")                st.subheader("📞 Görüşmeler")                st.dataframe(d["dv_b"], use_container_width=True)                st.markdown(f'[(📲 WhatsApp Gönder)]({wa_link("905492551912", report["msg"])})')    # --- 📝 TAB 4: PERSONEL RAPOR GÖNDERME ---    if role == "staff":        with tabs[3]:            st.header("📝 Kurucuya Günlük Raporu İlet")            report = generate_detailed_report(datetime.now().strftime("%Y-%m-%d"))            if report:                st.write(f"Bugünkü Toplam Gelir: **{report['data']['t_gelir']:,.0f} TL**")                st.markdown(f'### [(📲 RAPORU TUFAN BEY\'E GÖNDER)]({wa_link("905492551912", report["msg"])})')    # --- 📈 TAB 5: ANALİZ ---    if role == "admin":        with tabs[4]:            st.header("📈 Finansal Analiz")            # Analiz kodları...